import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { featureconfigFieldCapRule } from "./featureconfig-field-cap.rule.js";

function makeFields(count: number): string {
  const fields: string[] = [];
  for (let i = 1; i <= count; i++) {
    fields.push(`field_${i}: int32 = ${i};`);
  }
  return fields.join("\n    ");
}

describe("featureconfig-field-cap rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(
      runner,
      featureconfigFieldCapRule,
      "@a10n/blueprint-typespec",
    );
  });

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_featureconfig_field_cap
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T003.T003_01
    it("@featureConfig model with 0 fields passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            @featureConfig
            model MyConfig {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T003.T003_02
    it("@featureConfig model with exactly 10 fields passes", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            @featureConfig
            model MyConfig {
              ${makeFields(10)}
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T003.T003_03
    it("model without @featureConfig is ignored even with many fields", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            model PlainModel {
              ${makeFields(15)}
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T003.T003_04
    it("@featureConfig model with 11 fields emits warning", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            @featureConfig
            model MyConfig {
              ${makeFields(11)}
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/featureconfig-field-cap",
          message: /11 fields/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T003.T003_05
    it("message includes the model name", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.MyFeature {
            @featureConfig
            model ErrorRecoveryConfig {
              ${makeFields(11)}
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/featureconfig-field-cap",
          message: /ErrorRecoveryConfig/,
        });
    });
  });
});
